// Example 1: Manual discount calculation for a specific scenario
static void checkCustomerDiscount(Args _args)
{
    PriceDisc           priceDisc;
    SalesLine           salesLine;
    InventDim           inventDim;
    PriceDiscTable      priceDiscTable;
    CustTable           custTable;

    // Set up test data
    salesLine = SalesLine::find("SO-000123", 1.0); // Replace with actual sales order
    custTable = CustTable::find(salesLine.CustAccount);
    inventDim = InventDim::find(salesLine.InventDimId);

    // Create PriceDisc instance for line discount calculation
    priceDisc = PriceDisc::construct(
        ModuleInventPurchSales::Sales,
        salesLine.ItemId,
        inventDim,
        salesLine.SalesUnit,
        systemDateGet(),
        salesLine.SalesQty,
        salesLine.CustAccount,
        salesLine.CurrencyCode);

    // Find line discount
    if (priceDisc.findLineDisc(inventDim.InventDimId))
    {
        info(strFmt("Line discount found: %1%% = %2", 
                    priceDisc.lineDiscPct(), 
                    priceDisc.lineDiscAmount()));
        info(strFmt("Discount table RecId: %1", priceDisc.discTable().RecId));
    }
    else
    {
        info("No line discount found");
    }

    // Find multiline discount
    if (priceDisc.findMultiLineDisc(inventDim.InventDimId))
    {
        info(strFmt("Multiline discount: %1%% = %2", 
                    priceDisc.percent1(), 
                    priceDisc.discAmount()));
    }

    // Show all applicable discount agreements
    while select priceDiscTable
        where priceDiscTable.Relation == PriceDiscType::LineDiscSales
        && priceDiscTable.AccountCode <= TableGroupAll::GroupId
        && (priceDiscTable.AccountRelation == salesLine.CustAccount ||
            priceDiscTable.AccountRelation == custTable.LineDisc)
        && priceDiscTable.ItemCode <= TableGroupAll::GroupId
        && (priceDiscTable.ItemRelation == salesLine.ItemId ||
            priceDiscTable.ItemRelation == InventTable::find(salesLine.ItemId).ItemGroupId)
        && priceDiscTable.FromDate <= systemDateGet()
        && (priceDiscTable.ToDate == dateNull() || priceDiscTable.ToDate >= systemDateGet())
    {
        info(strFmt("Agreement: Account %1, Item %2, Qty %3+, Discount %4%%",
                    priceDiscTable.AccountRelation,
                    priceDiscTable.ItemRelation,
                    priceDiscTable.QuantityAmount,
                    priceDiscTable.Percent1));
    }
}

// Example 2: Trace discount calculation on SalesLine
// Add this to SalesLine.setPriceDisc() method to debug
void setPriceDiscDebug(InventDim _inventDim = InventDim::find(this.InventDimId))
{
    PriceDisc       priceDisc;
    boolean         priceFound, lineDiscFound, multiLineDiscFound;

    info(strFmt("=== Discount calculation for Item %1, Customer %2 ===", 
                this.ItemId, this.CustAccount));

    // Create price/discount calculator
    priceDisc = PriceDisc::construct(
        ModuleInventPurchSales::Sales,
        this.ItemId,
        _inventDim,
        this.SalesUnit,
        this.ShippingDateRequested ? this.ShippingDateRequested : systemDateGet(),
        this.SalesQty,
        this.CustAccount,
        this.CurrencyCode);

    // Find price agreement
    priceFound = priceDisc.findPrice(_inventDim.InventDimId);
    if (priceFound)
    {
        info(strFmt("Price found: %1 per %2 %3", 
                    priceDisc.price(), priceDisc.priceUnit(), this.SalesUnit));
        this.SalesPrice = priceDisc.price();
    }
    else
    {
        info("No price agreement found - using item master price");
    }

    // Find line discount
    lineDiscFound = priceDisc.findLineDisc(_inventDim.InventDimId);
    if (lineDiscFound)
    {
        info(strFmt("Line discount: %1%% = %2", 
                    priceDisc.lineDiscPct(), priceDisc.lineDiscAmount()));
        this.LinePercent = priceDisc.lineDiscPct();
        this.LineDisc = priceDisc.lineDiscAmount();
    }
    else
    {
        info("No line discount found");
        this.LinePercent = 0;
        this.LineDisc = 0;
    }

    // Recalculate line amount - use the actual SalesLine method
    this.LineAmount = (this.SalesQty * this.SalesPrice) - this.LineDisc;

    info(strFmt("Final line amount: %1", this.LineAmount));
}

// Example 3: Query to find all discount setups for a customer
static void showCustomerDiscountSetup(Args _args)
{
    CustAccount         custAccount = "CUST-001"; // Replace with actual customer
    PriceDiscTable      priceDiscTable;
    CustTable           custTable;

    custTable = CustTable::find(custAccount);

    info(strFmt("Discount setup for customer %1:", custAccount));
    info(strFmt("Customer line discount group: %1", custTable.LineDisc));
    info(strFmt("Customer multiline discount group: %1", custTable.MultiLineDisc));
    info(strFmt("Customer end discount group: %1", custTable.EndDisc));

    // Show all line discount agreements
    while select priceDiscTable
        where priceDiscTable.Relation == PriceDiscType::LineDiscSales
        && ((priceDiscTable.AccountCode == TableGroupAll::Table && 
             priceDiscTable.AccountRelation == custAccount) ||
            (priceDiscTable.AccountCode == TableGroupAll::GroupId && 
             priceDiscTable.AccountRelation == custTable.LineDisc))
        && priceDiscTable.FromDate <= systemDateGet()
        && (priceDiscTable.ToDate == dateNull() || priceDiscTable.ToDate >= systemDateGet())
    {
        info(strFmt("Line discount: Item %1, Qty %2+, Discount %3%%",
                    priceDiscTable.ItemRelation,
                    priceDiscTable.QuantityAmount,
                    priceDiscTable.Percent1));
    }
}

